/* Return the largest sum of any contiguous subarray in the vector x.
   Implementation uses Kadane's algorithm (O(n)).
*/
int maximumSubarray(const std::vector<int>& x) {
    if (x.empty()) return std::numeric_limits<int>::lowest();

    int max_current = x[0];
    int max_global = x[0];

    for (size_t i = 1; i < x.size(); ++i) {
        // Update max_current: either start new subarray at x[i] or extend
        max_current = std::max(x[i], max_current + x[i]);

        // Update max_global if a larger sum was found
        if (max_current > max_global)
            max_global = max_current;
    }
    return max_global;
}
