        for (std::size_t i = 0; i < n; ++i) {
            // All strings are assumed non-empty and lowercase.
            const unsigned char c = static_cast<unsigned char>(s[i][0]);
            local_bins[c - 'a'] += 1;
        }

        // Merge local counts into the global result.
