// Inline and constexpr for minimal overhead
inline constexpr bool isPowerOfTwo(int x) noexcept {
    return (x > 0) && static_cast<unsigned>(x & (x - 1)) == 0u;
}

/*
 * Apply the isPowerOfTwo function to every value in x and store the results in mask.
 * The function is thread‑safe and uses OpenMP to parallelise the loop on all available
 * hardware threads (configured via the standard OMP_NUM_THREADS environment variable).
 */
void mapPowersOfTwo(const std::vector<int>& x, std::vector<bool>& mask) noexcept {
    const std::size_t n = x.size();

    // Ensure mask has the same size as x (the harness guarantees this, but we guard
    // against accidental misuse in isolation)
    if (mask.size() < n) {
        mask.resize(n);
    }

    // Parallelize the loop. The *omp parallel for* pragma is cheap and gives
    // near‑linear speedup on the target 8‑core machine while keeping the code
    // identical in behavior (no reordering of writes occurs because each
    // thread writes to distinct indices).
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        mask[i] = isPowerOfTwo(x[i]);
    }
}
