#pragma once
#include <vector>
#include <algorithm>

int largestComponent(const std::vector<int> &A, size_t N) {
    // Use a vector of unsigned char for faster access / memory layout
    std::vector<unsigned char> visited(N, 0);
    int maxCount = 0;

    // Temporary stack reused for all components
    std::vector<int> stack;
    stack.reserve(N);

    for (int start = 0; start < static_cast<int>(N); ++start) {
        if (visited[start]) continue;

        // Depth‑first search using an explicit stack
        stack.clear();
        stack.push_back(start);
        visited[start] = 1;
        int count = 0;

        while (!stack.empty()) {
            int node = stack.back();
            stack.pop_back();
            ++count;

            const int base = node * static_cast<int>(N);
            for (int i = 0; i < static_cast<int>(N); ++i) {
                if (A[base + i] == 1 && !visited[i]) {
                    visited[i] = 1;
                    stack.push_back(i);
                }
            }
        }

        if (count > maxCount) maxCount = count;
    }

    return maxCount;
}
