#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <omp.h>

inline bool reduceLogicalXOR(const std::vector<bool>& x) {
    // vector<bool> stores bits packed into std::vector<bool>::reference.
    // We can treat the underlying memory as a sequence of uint64_t for speed.
    const std::size_t n     = x.size();
    const std::size_t chunk = 64;          // bits per uint64_t
    const std::size_t blocks = n / chunk;
    const std::size_t tail   = n % chunk;

    // Pointer to the underlying packed bits.
    const uint64_t* data = reinterpret_cast<const uint64_t*>(x.data());

    int parity = 0;

    // Parallel reduction of block parity.
#pragma omp parallel for reduction(⊕:parity)
    for (std::size_t i = 0; i < blocks; ++i) {
        parity ^= __builtin_popcountll(data[i]) & 1;
    }

    // Handle remaining bits that do not fill a full word.
    for (std::size_t i = 0; i < tail; ++i) {
        if (x[blocks * chunk + i])
            parity ^= 1;
    }

    return parity != 0;
}
