#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement
{
    std::size_t row, column;
    double      value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N.
*/
inline void spmv(double alpha,
                 std::vector<COOElement> const& A,
                 std::vector<double> const& x,
                 double beta,
                 std::vector<double>& y,
                 std::size_t /*M*/,
                 std::size_t /*N*/)
{
    /* Scale y by beta in parallel */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i)
    {
        y[i] *= beta;
    }

    /* Accumulate contributions in parallel; use atomic updates to avoid
       race conditions on entries with multiple incoming COO terms. */
#pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < A.size(); ++k)
    {
        const COOElement& el = A[k];
        /* Bounds are guaranteed by the original implementation; we keep them
           for correctness but avoid repeated operator-> chaining. */
        double prod = alpha * el.value * x[el.column];
        #pragma omp atomic
        y[el.row] += prod;
    }
}
