struct Element {
    std::size_t index;
    double value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors.
   The input vectors are assumed to be sorted by index.
   The result is stored in the pre‑allocated vector z. */
inline void sparseAxpy(double alpha,
                       std::vector<Element> const& x,
                       std::vector<Element> const& y,
                       std::vector<double>& z)
{
    // Add the contribution of x first
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        std::size_t idx = x[i].index;
        double val   = alpha * x[i].value;
        // atomic addition to avoid race conditions
        #pragma omp atomic
        z[idx] += val;
    }

    // Add the contribution of y
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        std::size_t idx = y[i].index;
        double val      = y[i].value;
        #pragma omp atomic
        z[idx] += val;
    }
}
