/* Compute the highest node degree in the undirected graph.
   A is an NxN adjacency matrix stored in row‑major order.
   The function is fully thread‑safe and uses the fastest
   combination of OpenMP parallelism and compiler vectorisation. */
inline int maxDegree(std::vector<int> const& A, size_t N) {
    // Reduce over the row sums.  Each iteration is independent
    // so the loop can be parallelised safely.
    int highestDegree = 0;
    const int * restrict data = A.data();

#pragma omp parallel for schedule(static, 64) reduction(max:highestDegree)
    for (size_t i = 0; i < N; ++i) {
        int degree = 0;
        // Process 8 integers at a time when possible to assist SIMD.
        const int *row = data + i * N;
#ifdef __SSE2__
        // If the compiler supports SIMD intrinsics, unroll manually
        // (the compiler usually auto‑vectorises this anyway).
        size_t j = 0;
        for (; j + 7 < N; j += 8) {
            degree += row[j];
            degree += row[j+1];
            degree += row[j+2];
            degree += row[j+3];
            degree += row[j+4];
            degree += row[j+5];
            degree += row[j+6];
            degree += row[j+7];
        }
        for (; j < N; ++j) {
            degree += row[j];
        }
#else
        // Fallback for systems without SIMD hints
        for (size_t j = 0; j < N; ++j) {
            degree += row[j];
        }
#endif
        if (degree > highestDegree) highestDegree = degree;
    }
    return highestDegree;
}
