/* Count how many elements of `x` fall into each of the four fractional
   quartile bins and store the counts in `bins`.  The function is
   parallelized with OpenMP, compiled with –O2 and –fopenmp.  The
   algorithm is identical to the original sequential implementation. */
inline void countQuartiles(const std::vector<double>& x, std::array<size_t, 4>& bins)
{
    // Reset output bins
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Work in one pass;  OpenMP will split the loop among the threads.
    // `reduction(+:bins[0],bins[1],bins[2],bins[3])` would also work,
    // but explicit casts avoid GCC warnings about non-atomic reductions
    // on array elements.
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(x.size()); ++i) {
        const double val = x[i];
        // The fractional part of a double is val – floor(val).
        // floor() is fast enough and correctly handles negatives.
        const double frac = val - std::floor(val);

        // Determine which quartile the fraction falls into.
        // Branches are implicitly predicted; the compiler will
        // generate a compact test sequence.
        if (frac < 0.25) {
            #pragma omp atomic
            ++bins[0];
        } else if (frac < 0.5) {
            #pragma omp atomic
            ++bins[1];
        } else if (frac < 0.75) {
            #pragma omp atomic
            ++bins[2];
        } else {
            #pragma omp atomic
            ++bins[3];
        }
    }
}
