#pragma once
#include <vector>
#include <cstdint>
#include <numeric>
#include <omp.h>

int64_t sumOfPrefixSum(std::vector<int64_t> const& x) {
    size_t n = x.size();
    if (n == 0) return 0;

    // Choose chunk size (tuned for performance)
    const size_t chunks = omp_get_max_threads() * 2;
    const size_t chunk_size = (n + chunks - 1) / chunks;

    // Step 1: compute local inclusive scans and chunk totals
    std::vector<int64_t> local_sum(chunks, 0);
    std::vector<int64_t> temp_prefix(n, 0);

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        size_t start = tid * chunk_size;
        if (start >= n) return;
        size_t end = std::min(start + chunk_size, n);

        // inclusive scan in local chunk
        int64_t sum = 0;
        for (size_t i = start; i < end; ++i) {
            sum += x[i];
            temp_prefix[i] = sum;
        }
        local_sum[tid] = sum;
    }

    // Step 2: prefix sums of chunk totals
    for (size_t i = 1; i < chunks; ++i) {
        local_sum[i] += local_sum[i - 1];
    }

    // Step 3: adjust each chunk by preceding total
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        if (tid == 0) return;
        size_t start = tid * chunk_size;
        if (start >= n) return;
        int64_t offset = local_sum[tid - 1];
        size_t end = std::min(start + chunk_size, n);
        for (size_t i = start; i < end; ++i) {
            temp_prefix[i] += offset;
        }
    }

    // Step 4: sum all prefix values
    return std::accumulate(temp_prefix.begin(), temp_prefix.end(), int64_t{0});
}
