/*
 * Count how many elements of `x` fall into each 10‑unit bin
 * [0,10), [10,20), …, [90,100].  The result is stored in `bins`.
 *
 * Assumptions:
 *   * Every value in `x` is in the closed interval [0, 100].
 *   * The array `bins` is pre‑initialised to zero by the caller.
 *
 * The implementation is fully parallelised with OpenMP and uses
 * efficient integer arithmetic to minimise Branch‑prediction
 * overhead.  Because the division is deterministic and all
 * values are bounded, the compiler can optimise the division
 * into a multiplication by a pre‑computed reciprocal.
 */
inline void binsBy10Count(const std::vector<double> &x,
                          std::array<std::size_t, 10> &bins)
{
    constexpr double inv10 = 0.1;           // 1/10
    const std::size_t n = x.size();

    // Temporary per‑thread accumulators to avoid atomic operations.
    std::vector<std::array<std::size_t, 10>> private_bins(omp_get_max_threads());

    #pragma omp parallel
    {
        const int    tid   = omp_get_thread_num();
        auto &       local = private_bins[tid];

        // Initialise local counters to zero.
        std::fill(local.begin(), local.end(), static_cast<std::size_t>(0));

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i)
        {
            // Convert to an integer bin index. Since all values are
            // in [0,100], the result is always in [0,10].
            std::size_t bin = static_cast<std::size_t>(x[i] * inv10);
            ++local[bin];
        }
    }

    // Combine all thread‑local counts into the final result.
    for (int t = 0; t < static_cast<int>(private_bins.size()); ++t)
        for (std::size_t b = 0; b < 10; ++b)
            bins[b] += private_bins[t][b];
