inline double closestPair(std::vector<double> const& x) {
    // Return 0 for vectors with fewer than 2 elements, matching the original behaviour.
    if (x.size() < 2) return 0.0;

    // Work on a local copy so that sorting does not modify the caller’s data.
    std::vector<double> v = x;
    std::sort(v.begin(), v.end());

    // Parallel reduction to find the minimum adjacent difference.
    // The algorithm is correct because after sorting, the closest pair must be adjacent.
    const size_t n = v.size();
    double minDist = std::numeric_limits<double>::max();

    #pragma omp parallel for reduction(min:minDist)
    for (size_t i = 0; i + 1 < n; ++i) {
        double d = std::fabs(v[i+1] - v[i]);   // std::abs for double is std::fabs
        if (d < minDist) minDist = d;
    }

    return minDist;
