#include <omp.h>

/* Compute the inclusive prefix sum of the input vector `x` into `output`.
 * The operation is performed in parallel using a work‑sharing
 * algorithm that is compatible with GCC‑OpenMP on x86‑64.
 *
 * Example:
 *   input:  [1, 7, 4, 6, 6, 2]
 *   output: [1, 8,12,18,24,26]
 */
inline void prefixSum(const std::vector<int64_t> &x, std::vector<int64_t> &output) {
    const std::size_t N = x.size();
    if (N == 0) {
        output.clear();
        return;
    }

    /* Ensure output has the same size as the input. */
    output.resize(N);

    /* Step 1 – compute block sums in parallel. */
    int num_threads = omp_get_max_threads();
    std::vector<int64_t> block_sums(num_threads, 0);

#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::size_t chunk = (N + num_threads - 1) / num_threads;
        std::size_t start = tid * chunk;
        std::size_t end   = (tid + 1) * chunk;
        if (end > N) end = N;

        int64_t local_sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            local_sum += x[i];
            output[i] = local_sum;        // first local scan
        }
        block_sums[tid] = local_sum;      // store block total
    }

    /* Step 2 – accumulate block sums serially. */
    int64_t carry = 0;
    for (int i = 0; i < static_cast<int>(block_sums.size()); ++i) {
        int64_t tmp = block_sums[i];
        block_sums[i] = carry;
        carry += tmp;
    }

    /* Step 3 – add the carried amount to each block in parallel. */
#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::size_t chunk = (N + num_threads - 1) / num_threads;
        std::size_t start = tid * chunk;
        std::size_t end   = (tid + 1) * chunk;
        if (end > N) end = N;

        int64_t offset = block_sums[tid];
        for (std::size_t i = start; i < end; ++i) {
            output[i] += offset;
        }
    }
}
