#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Deep copy of COO matrix into a dense N×N array */
static inline void to_dense(const std::vector<COOElement>& A,
                            std::vector<double>& dense,
                            size_t N)
{
    dense.assign(N * N, 0.0);
    for (const auto& e : A)
        dense[e.row * N + e.column] = e.value;
}

/*
 * LU factorization (Doolittle) of a dense N×N matrix.
 * L is stored with unit diagonal in the lower triangle, U in the upper.
 * The matrix is provided in dense row‑major form.
 * The routine is thread‑safe; each iteration of the outer loop is
 * independent and can be executed in parallel.
 */
template<class T>
static inline void lu_dense_ref(const std::vector<T>& matrix,
                                std::vector<double>& L,
                                std::vector<double>& U,
                                size_t N)
{
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

#pragma omp parallel for schedule(static)
    for (long i = 0; i < static_cast<long>(N); ++i) {
        const double* row_i = matrix.data() + i * N;

        /*-------------------- U row i --------------------------------*/
        for (size_t j = i; j < N; ++j) {
            double sum = row_i[j];
            for (size_t k = 0; k < i; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = sum;
        }

        /*-------------------- L column i --------------------------------*/
        for (size_t j = i + 1; j < N; ++j) {
            /* L[i][j] is not used – compute it directly */
            double sum = matrix[j * N + i];
            for (size_t k = 0; k < i; ++k)
                sum -= L[j * N + k] * U[k * N + i];
            L[j * N + i] = sum / U[i * N + i];
        }

        /* unit diagonal of L */
        L[i * N + i] = 1.0;
    }
}

/*
 * Public interface matching the original signature.
 * It accepts a COO‑boxed sparse matrix, turns it into a dense matrix,
 * and then performs an efficient (parallel) LU factorization.
 */
inline void luFactorize(const std::vector<COOElement>& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        size_t N)
{
    std::vector<double> full(N * N);
    to_dense(A, full, N);
    lu_dense_ref(full, L, U, N);
}
