#pragma once
#include <vector>
#include <cstdlib>
#include <cmath>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:
   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
inline void solveLinearSystem(
    std::vector<COOElement> const& A,
    std::vector<double> const& b,
    std::vector<double> &x,
    size_t N)
{
    // Allocate a flat matrix storage (row-major)
    std::vector<double> matrix(N * N, 0.0);

    // Populate matrix from COO
    for (auto const& e : A)
        matrix[e.row * N + e.column] = e.value;

    // Working copy of RHS
    std::vector<double> rhs = b;

    // Gaussian elimination with partial pivoting
    for (size_t i = 0; i < N; ++i) {
        // Pivot search
        size_t maxRow = i;
        double maxVal = std::fabs(matrix[i * N + i]);
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::fabs(matrix[k * N + i]);
            if (val > maxVal) {
                maxVal = val;
                maxRow = k;
            }
        }

        // Swap rows if needed
        if (maxRow != i) {
            for (size_t j = i; j < N; ++j)
                std::swap(matrix[i * N + j], matrix[maxRow * N + j]);
            std::swap(rhs[i], rhs[maxRow]);
        }

        double pivot = matrix[i * N + i];
        // Eliminate rows below
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -matrix[k * N + i] / pivot;
            matrix[k * N + i] = 0.0;                 // explicitly zero
            for (size_t j = i + 1; j < N; ++j)
                matrix[k * N + j] += factor * matrix[i * N + j];
            rhs[k] += factor * rhs[i];
        }
    }

    // Back substitution
    x.resize(N);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = rhs[i];
        for (int j = static_cast<int>(i) + 1; j < static_cast<int>(N); ++j)
            sum -= matrix[i * N + j] * x[j];
        x[i] = sum / matrix[i * N + i];
    }
}
