inline void jacobi1D(std::vector<double> const& input, std::vector<double>& output)
{
    const size_t n = input.size();
    if (n == 0) return;

    const double inv3 = 1.0 / 3.0;

    /* The vector prefers a contiguous block of memory.  We use
       pointer arithmetic to let the compiler inside the loop
       employ SIMD instructions, while the OpenMP parallel for
       distributes the work between threads. */
    const double* x = input.data();
    double* y = output.data();

    /* Handle the first element explicitly to avoid an if-test
       inside the parallel loop. */
    y[0] = (x[0] + x[1]) * inv3;
    /* Handle the last element explicitly. */
    if (n > 1) y[n-1] = (x[n-2] + x[n-1]) * inv3;

    /* Parallel loop over the interior elements. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 1; i + 1 < n; ++i) {
        y[i] = (x[i-1] + x[i] + x[i+1]) * inv3;
    }
