/* FFT implementation – radix‑2 iterative Cooley‑Tukey.
 * Input:  x    – complex<double> vector (power of two length)
 * Output: r,i   – real/imag parts of the FFT (in the same order)
 *
 * The routine preserves the exact numerical results of the reference
 * implementation while exploiting multiple threads, pre‑computed
 * twiddle factors and a lock‑step bit‑reversal step that runs
 * efficiently on 64‑bit machines.
 */

static inline void fft_precomputation(std::vector<std::complex<double>>& rev,
                                      std::vector<std::complex<double>>& tw,
                                      unsigned int n)
{
    unsigned int m = 0, tmp;
    for (tmp = n; tmp > 1; tmp >>= 1) ++m;       // log2(n)

    // Bit reversal permutation
    rev.resize(n);
    for (unsigned int i = 0; i < n; ++i) {
        unsigned int x = i, y = 0;
        for (unsigned int j = 0; j < m; ++j) {
            y = (y << 1) | (x & 1);
            x >>= 1;
        }
        rev[i] = std::complex<double>(static_cast<double>(y), 0.0);
    }

    // Pre‑compute twiddle factors
    tw.resize(n/2);
    const double pi = M_PI;
    for (unsigned int k = 0; k < n/2; ++k) {
        double angle = -2.0 * pi * k / n;
        tw[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }
}

void fft(const std::vector<std::complex<double>>& x,
         std::vector<double>& r,
         std::vector<double>& i)
{
    const unsigned int n = static_cast<unsigned int>(x.size());
    std::vector<std::complex<double>> a(x);          // working copy
    std::vector<std::complex<double>> rev, tw;
    fft_precomputation(rev, tw, n);

    // Bit‑reversal step (in‑place)
    for (unsigned int j = 0; j < n; ++j) {
        unsigned int i = static_cast<unsigned int>(rev[j].real());
        if (i > j)
            std::swap(a[i], a[j]);
    }

    // Cooley‑Tukey radix‑2 butterfly
    for (unsigned int len = 2; len <= n; len <<= 1) {
        unsigned int half = len >> 1;
        unsigned int step = n / len;
        #pragma omp parallel for schedule(static)
        for (unsigned int i = 0; i < n; i += len) {
            for (unsigned int j = 0; j < half; ++j) {
                unsigned int k = j * step;
                std::complex<double> t = a[i + j + half] * tw[k];
                std::complex<double> u = a[i + j];
                a[i + j]     = u + t;
                a[i + j + half] = u - t;
            }
        }
    }

    // Split into real / imaginary vectors (no temporary needed)
    r.resize(n);
    i.resize(n);
    for (unsigned int j = 0; j < n; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
