/* Convolve the edge kernel with a grayscale image.
 *
 *  imageIn  : input image (row‑major, size N*N)
 *  imageOut : output image (must be pre‑allocated with N*N ints)
 *  N        : image dimension
 *
 *  The function is parallelised with OpenMP and uses pointer arithmetic
 *  for maximum speed while preserving the exact behaviour of the
 *  reference implementation.
 */
void convolveKernel(std::vector<int> const& imageIn,
                    std::vector<int> &imageOut,
                    size_t N)
{
    const int *in  = imageIn.data();
    int       *out = imageOut.data();

    /* parallelise over outer two loops */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        for (int j = 0; j < static_cast<int>(N); ++j) {
            int sum = 0;

            /* 3×3 neighbourhood */
            for (int di = -1; di <= 1; ++di) {
                int ni = i + di;
                if (ni < 0 || ni >= static_cast<int>(N)) continue;
                for (int dj = -1; dj <= 1; ++dj) {
                    int nj = j + dj;
                    if (nj < 0 || nj >= static_cast<int>(N)) continue;
                    sum += in[ni * static_cast<int>(N) + nj] *
                           edgeKernel[di + 1][dj + 1];
                }
            }
            out[i * static_cast<int>(N) + j] = clip(sum);
        }
    }
}
