/* Return the area of the smallest triangle that can be formed by any 3 points.
   Example:
   input: [{0, 10}, {5, 5}, {1,0}, {-1, 1}, {-10, 0}]
   output: 5.5
*/
inline double smallestArea(const std::vector<Point>& points) {
    const size_t n = points.size();
    if (n < 3) return 0.0;

    // Use a thread‑local minimum to avoid atomic contention
    std::vector<double> localMin(omp_get_max_threads(),
                                 std::numeric_limits<double>::max());

    #pragma omp parallel for schedule(static, 8)
    for (size_t i = 0; i < n - 2; ++i) {
        const std::thread::id tid = std::this_thread::get_id();
        const int thread_idx = omp_get_thread_num();
        double& local = localMin[thread_idx];

        for (size_t j = i + 1; j < n - 1; ++j) {
            const double *aj = &points[j];
            for (size_t k = j + 1; k < n; ++k) {
                const double area = triAreaPts(points[i], *aj, points[k]);
                if (area < local) local = area;
            }
        }
    }

    // Reduce the per‑thread minima
    double minArea = std::numeric_limits<double>::max();
    for (double v : localMin)
        if (v < minArea) minArea = v;

    return minArea;
}
