#  define M_PI 3.14159265358979323846
#endif

/*** Fast iterative radix‑2 FFT (in‑place) ***/
static inline void fft_impl(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    /* Bit‑reversal permutation */
    std::size_t j = 0;
    for (std::size_t i = 1; i < N; ++i)
    {
        std::size_t bit = N >> 1;
        for (; j & bit; bit >>= 1) j ^= bit;
        j ^= bit;
        if (i < j) std::swap(x[i], x[j]);
    }

    /* Pre‑compute roots of unity */
    std::vector<std::complex<double>> twiddles(N / 2);
    double ang = -2.0 * M_PI / N;
    std::complex<double> w(1.0, 0.0);
    std::complex<double> wn(std::cos(ang), std::sin(ang));
    for (std::size_t i = 0; i < N / 2; ++i)
    {
        twiddles[i] = w;
        w *= wn;
    }

    /* Cooley‑Tukey iterative FFT with OpenMP parallelism */
    for (std::size_t len = 2; len <= N; len <<= 1)
    {
        const std::size_t step = len >> 1;
        const std::size_t twiddleStep = N / len;
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += len)
        {
            std::size_t t = 0;
            for (std::size_t j = 0; j < step; ++j)
            {
                std::complex<double> u = x[i + j];
                std::complex<double> v = x[i + j + step] * twiddles[t * twiddleStep];
                x[i + j]         = u + v;
                x[i + j + step] = u - v;
                ++t;
            }
        }
    }
}

/*** Inverse FFT: conjugate–transform–conjugate and scale ***/
void ifft(std::vector<std::complex<double>>& x)
{
    for (auto& c : x) c = std::conj(c);
    fft_impl(x);
    for (auto& c : x) c = std::conj(c);
    const double invN = 1.0 / static_cast<double>(x.size());
    for (auto& c : x) c *= invN;
}
