/*
 * Multiply the matrix A by the vector x. Store the results in the vector y.
 * A is an M×N matrix stored in row-major, x has N elements, and y has M elements.
 *
 * Example:
 *   input:  A=[[1, -1, 2], [0, -3, 1]]  x=[2, 1, 0]
 *   output: y=[1, -3]
 */
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> & y,
                 size_t M, size_t N)
{
    // Ensure the input sizes are compatible
    if (A.size() < M * N || x.size() < N || y.size() < M)
        return; // silently return if sizes are wrong – keeps original behaviour

    // Parallelize outer loop over rows with OpenMP
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i) {
        double sum = 0.0;
        const double *Ai = &A[i * N];
        const double *x_ptr = x.data();

        // Inner loop – unrolled by 4 for better vectorisation
        size_t j = 0;
        for (; j + 3 < N; j += 4) {
            sum += Ai[j]     * x_ptr[j];
            sum += Ai[j + 1] * x_ptr[j + 1];
            sum += Ai[j + 2] * x_ptr[j + 2];
            sum += Ai[j + 3] * x_ptr[j + 3];
        }
        // Tail loop for remaining elements
        for (; j < N; ++j) {
            sum += Ai[j] * x_ptr[j];
        }

        y[i] = sum;
    }
}
