/* Simulate one generation of Game of Life on `input`. Store the results in `output`.
   `input` and `output` are NxN grids stored in row-major.
   The algorithm follows the classic rules.
   This implementation is cache‑friendly and uses OpenMP for parallelism.
   The original semantics are preserved exactly. */
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       size_t N) {
    // Ensure output has the right size
    if (output.size() != N * N) output.resize(N * N);

    const int *in = input.data();
    int *out = output.data();
    const size_t stride = N;   // row length

    // Parallelise over rows; inner loop is the fast varying index.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t idx = i * stride;
        for (size_t j = 0; j < N; ++j) {
            const int cur = in[idx + j];
            int sum = 0;

            // north / south
            if (i > 0)     sum += in[(i-1)*stride + j];
            if (i + 1 < N) sum += in[(i+1)*stride + j];

            // west / east
            if (j > 0)     sum += in[idx + j-1];
            if (j + 1 < N) sum += in[idx + j+1];

            // four corners
            if (i > 0 && j > 0)         sum += in[(i-1)*stride + j-1];
            if (i > 0 && j + 1 < N)     sum += in[(i-1)*stride + j+1];
            if (i + 1 < N && j > 0)     sum += in[(i+1)*stride + j-1];
            if (i + 1 < N && j + 1 < N) sum += in[(i+1)*stride + j+1];

            // Apply rules
            out[idx + j] = (cur == 1) ?
                ((sum == 2 || sum == 3) ? 1 : 0) :
                (sum == 3 ? 1 : 0);
        }
    }
}
