/* Compute the convex hull of `points` using the monotone chain
   algorithm. The result is written into `hull`. */
inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();
    if (n < 3) {                  // trivial cases
        hull = points;
        return;
    }

    // Work on a copy that we can freely sort / modify
    std::vector<Point> p(points);
    std::sort(p.begin(), p.end(), [](const Point& a, const Point& b) noexcept {
        return a.x < b.x || (a.x == b.x && a.y < b.y);
    });

    // Upper bound for hull vertices: 2*n (worst case for floating‐point duplicates)
    std::vector<Point> temp;
    temp.reserve(2 * n);
    std::size_t k = 0;   // number of points in temp

    /* Build lower hull */
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(temp[k - 2], temp[k - 1], p[i]) <= 0)
            --k;
        temp[k++] = p[i];
    }

    /* Build upper hull */
    const std::size_t start = k + 1;   // start index for the upper part
    for (std::size_t i = n; i-- > 1;) {
        while (k >= start && cross(temp[k - 2], temp[k - 1], p[i - 1]) <= 0)
            --k;
        temp[k++] = p[i - 1];
    }

    // Remove redundant last point (same as first)
    temp.resize(k - 1);
    hull.swap(temp);   // fast move into caller's hull
}
