static inline double dist(const Point& a, const Point& b) noexcept {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points.
   The implementation uses the Andrew monotone chain algorithm and parallelises the
   perimeter calculation.
*/
double convexHullPerimeter(std::vector<Point> const& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Make a copy and sort it
    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) noexcept {
        return a.x < b.x || (a.x == b.x && a.y < b.y);
    });

    // Upper and lower hull buffers
    std::vector<Point> hull(2 * n);
    std::size_t k = 0;

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(hull[k-2], hull[k-1], pts[i]) <= 0) {
            --k;
        }
        hull[k++] = pts[i];
    }

    // Build upper hull
    std::size_t t = k + 1;
    for (std::size_t i = n; i-- > 1; ) {
        while (k >= t && cross(hull[k-2], hull[k-1], pts[i-1]) <= 0) {
            --k;
        }
        hull[k++] = pts[i-1];
    }

    hull.resize(k - 1);  // last point repeats first

    // Parallel accumulation of distances
    double sum = 0.0;
    #pragma omp parallel for reduction(+:sum)
    for (std::size_t i = 0; i < hull.size(); ++i) {
        const std::size_t j = (i + 1) % hull.size();
        sum += dist(hull[i], hull[j]);
    }

    return sum;
}
