void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N) {
    if (N == 0) { x.clear(); return; }

    // Work on copies to avoid modifying inputs
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    double *a = A_copy.data();   // alias for speed
    double *bb = b_copy.data();  // alias for speed

    // Forward elimination – cache‑friendly + parallel
    for (size_t i = 0; i < N - 1; ++i) {
        double pivot = a[i * N + i];
        if (pivot == 0.0) return;              // singular -> abort

        // Parallel over rows below pivot
        #pragma omp parallel for schedule(static)
        for (ptrdiff_t j = i + 1; j < static_cast<ptrdiff_t>(N); ++j) {
            double factor = a[j * N + i] / pivot;
            double *row_j = a + j * N;
            double *row_i = a + i * N;
            for (size_t k = i; k < N; ++k) {
                row_j[k] -= factor * row_i[k];
            }
            bb[j] -= factor * bb[i];
        }
    }

    // Back substitution – serial is fast enough for the small inner dimension
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        double *row_i = a + i * N;
        for (size_t j = i + 1; j < N; ++j) {
            sum += row_i[j] * x[j];
        }
        x[i] = (bb[i] - sum) / a[i * N + i];
    }
}
