/* Optimised matrix multiplication A (M×K) × B (K×N) → C (M×N).
   All matrices are stored in row-major order.
   The routine respects the semantics of the original implementation
   (C is not cleared before accumulation); the caller must initialise C
   to zero if required.
   The code uses block tiling, SIMD-friendly access patterns,
   and OpenMP parallelisation across the outermost loop.
*/
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // Block sizes tuned for typical L1/L2 cache on recent Intel/AMD CPUs.
    constexpr size_t BM = 64;   // M dimension block size
    constexpr size_t BK = 64;   // K dimension block size
    constexpr size_t BN = 256;  // N dimension block size

    // Parallelise over the outer M-blocks
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BM) {
        size_t i_max = std::min(ii + BM, M);
        for (size_t jj = 0; jj < N; jj += BN) {
            size_t j_max = std::min(jj + BN, N);
            for (size_t kk = 0; kk < K; kk += BK) {
                size_t k_max = std::min(kk + BK, K);

                // Compute local copy of block of B to improve temporal locality
                for (size_t i = ii; i < i_max; ++i) {
                    for (size_t k = kk; k < k_max; ++k) {
                        double a_val = A[i*K + k];
                        // Unroll the inner j-loop in blocks of 4 for vectorisation
                        size_t j = jj;
                        for (; j + 3 < j_max; j += 4) {
                            C[i*N + j]     += a_val * B[k*N + j];
                            C[i*N + j + 1] += a_val * B[k*N + j + 1];
                            C[i*N + j + 2] += a_val * B[k*N + j + 2];
                            C[i*N + j + 3] += a_val * B[k*N + j + 3];
                        }
                        // Tail handling
                        for (; j < j_max; ++j) {
                            C[i*N + j] += a_val * B[k*N + j];
                        }
                    }
                }
            }
        }
    }
}
