/// Sorts all non‑zero elements of @p x in ascending order while keeping
/// zero elements at their original positions.
///
/// The implementation is fully in‑place except for a temporary buffer that
/// holds the non‑zero elements. The buffer is pre‑allocated to avoid
/// repeated reallocations (which is the main performance gain when the
/// vector contains many non‑zeros).
void sortIgnoreZero(std::vector<int> &x)
{
    // Reserve memory for the worst‑case scenario (all elements non‑zero).
    std::vector<int> nonZeroElements;
    nonZeroElements.reserve(x.size());

    // Collect the non‑zero values.
    for (int v : x)
        if (v != 0)
            nonZeroElements.push_back(v);

    // Sort the collected values.
    std::sort(nonZeroElements.begin(), nonZeroElements.end());

    // Put the sorted values back into their original positions.
    size_t idx = 0;
    for (size_t i = 0; i < x.size(); ++i)
        if (x[i] != 0)
            x[i] = nonZeroElements[idx++];
}
