/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither.
   Examples:
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=7
   output: true
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=1
   output: false
*/
inline bool xorContains(const std::vector<int>& x,
                        const std::vector<int>& y,
                        int val)
{
    bool foundInX = false;
    const int* px = x.data();
    const int* endx = px + x.size();
    for (; px != endx; ++px)
        if (*px == val) { foundInX = true; break; }

    if (foundInX) {
        // if already found in X, we only need to check that it's *not* in Y
        const int* py = y.data();
        const int* endy = py + y.size();
        for (; py != endy; ++py)
            if (*py == val) return false; // found in both
        return true; // found only in X
    } else {
        // not in X, check Y
        const int* py = y.data();
        const int* endy = py + y.size();
        for (; py != endy; ++py)
            if (*py == val) return true; // found only in Y
        return false; // found in neither
    }
}
