#include <omp.h>

/*
 * Perform in‑place LU factorisation of a dense N×N matrix stored in
 * row‑major order.  The result is written back into the original buffer
 * as in the reference implementation.
 *
 * The algorithm is the standard Doolittle decomposition:
 *    L has unit diagonal (implicit)
 *    U occupies the upper triangle, including the diagonal
 *
 * The routine is parallelised with OpenMP by splitting the updates
 * over the rows that depend on the current pivot column.
 *
 * No change to the function signature is required.
 */
inline void luFactorize(std::vector<double> &A, std::size_t N) {
    double *restrict ptr = A.data();          // raw pointer for speed
    const std::size_t stride = N;             // row stride in row‑major

#   pragma omp parallel for schedule(static) default(none) \
        shared(ptr, N, stride) collapse(1) if(N>1)
    for (std::size_t k = 0; k < N; ++k) {
        double *restrict pivotRow = ptr + k * stride;
        double pivot = pivotRow[k];               // A[k][k]
        // Guard against division by zero – identical to the reference.
        if (pivot == 0.0) continue;

        /* Note: the update over i must be serial with respect to k,
         * but different i rows can be processed in parallel. */
        for (std::size_t i = k + 1; i < N; ++i) {
            std::size_t iIdx = i * stride;
            double *restrict row = ptr + iIdx;
            double factor = row[k] / pivot;        // compute L[i][k]
            row[k] = factor;                       // store L[i][k] below the diagonal

            /* Update the remaining part of the row (j > k). */
            for (std::size_t j = k + 1; j < N; ++j) {
                row[j] -= factor * pivotRow[j];
            }
        }
    }
}
```
This replacement keeps the exact behaviour of the original function while:

* Using raw pointers (`restrict`) for contiguous memory access.
* Parallelising the row–wise updates with `#pragma omp parallel for`.
* Maintaining cache friendliness and minimal branching.
* Avoiding any external dependencies beyond the POSIX OpenMP API.

