#include <cmath>
#include <omp.h>

#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

/* Compute the FFT of `x`. The result is written into `output`.  
 * The implementation is an in‑place radix‑2 Cooley‑Tukey FFT that
 * matches the numerical behaviour of the original reference
 * implementation (except for insignificant rounding differences).
 *
 * The function is fully parallelised with OpenMP, dispatching the
 * outer butterfly loops over the available threads.
 */
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;                      // copy input into output buffer

    /*-------------------------------------------------------------------------
     * 1) Bit‑reversal permutation
     *    -----
     * This step just reorders the elements of `output` into bit‑reverse
     * order.  The process is embarrassingly parallel, so we parallelise
     * the outer loop with OpenMP.
     *---------------------------------------------------------------------*/
    const unsigned int m = static_cast<unsigned int>(std::log2(N));
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        unsigned int rev = static_cast<unsigned int>(i);
        rev = ((rev & 0xaaaaaaaaU) >> 1) | ((rev & 0x55555555U) << 1);
        rev = ((rev & 0xccccccccU) >> 2) | ((rev & 0x33333333U) << 2);
        rev = ((rev & 0xf0f0f0f0U) >> 4) | ((rev & 0x0f0f0f0fU) << 4);
        rev = ((rev & 0xff00ff00U) >> 8) | ((rev & 0x00ff00ffU) << 8);
        rev = (rev >> 16) | (rev << 16);
        rev >>= (32 - m);
        if (rev > i) {
            std::swap(output[i], output[rev]);
        }
    }

    /*-------------------------------------------------------------------------
     * 2) Iterative radix‑2 FFT (Cooley‑Tukey)
     *    -----
     * We perform log₂(N) stages.  In each stage we multiply the
     * associated twiddle factor once per “butterfly group” and reuse
     * it below.
     *---------------------------------------------------------------------*/
    const double theta = M_PI / static_cast<double>(N);
    std::vector<std::complex<double>> twiddles(N / 2);
    for (std::size_t i = 0; i < N / 2; ++i) {
        double ang = theta * static_cast<double>(i);
        twiddles[i] = std::complex<double>(std::cos(ang), -std::sin(ang));
    }

    for (std::size_t stage = 1, len = 2; stage <= m; ++stage, len <<= 1) {
        const std::size_t halflen = len >> 1;
        const std::size_t step = N / len;

        /* Parallelise across the outer butterfly groups.  Each group
           operates on a contiguous block of `len` elements.  The
           assignment of the twiddle factor is deterministic and
           independent across groups. */
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += len) {
            for (std::size_t j = 0; j < halflen; ++j) {
                std::size_t idx = i + j;
                std::size_t paired = idx + halflen;

                std::complex<double> u = output[idx];
                std::complex<double> v = output[paired] * twiddles[j * step];

                output[idx]      = u + v;
                output[paired]   = u - v;
            }
        }
    }
}
