#pragma once
#include <vector>
#include <limits>
#include <algorithm>
#include <cmath>
#include <omp.h>

struct Point {
    double x, y;
};

static inline double dist(const Point& a, const Point& b) noexcept {
    double dx = a.x - b.x, dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Returns the distance between the closest pair of points.
   Algorithm: plane sweep with divide‑and‑conquer in O(n log n).
   Parallelised with OpenMP for the initial sort and a few recursive
   calls. */
double closestPair(std::vector<Point> const& points) {
    const size_t n = points.size();
    if (n < 2) return 0.0;

    /* copy and sort by X */
    std::vector<Point> pts(points);
    #pragma omp parallel sections
    {
        #pragma omp section
        {
            std::sort(pts.begin(), pts.end(),
                      [](const Point& a, const Point& b) { return a.x < b.x; });
        }
    }

    /* auxiliary buffer for merge step */
    std::vector<Point> aux(n);

    function<double(size_t, size_t)> rec = [&](size_t l, size_t r) -> double {
        if (r - l <= 3) {
            double d = std::numeric_limits<double>::max();
            for (size_t i = l; i < r; ++i)
                for (size_t j = i + 1; j < r; ++j)
                    d = std::min(d, dist(pts[i], pts[j]));
            /* sort by Y for the small set */
            std::sort(pts.begin() + l, pts.begin() + r,
                      [](const Point& a, const Point& b) { return a.y < b.y; });
            return d;
        }

        size_t mid = (l + r) / 2;
        double midX = pts[mid].x;

        double dl, dr;
        #pragma omp task shared(dl) default(none) firstprivate(pts, aux, l, mid) 
        { dl = rec(l, mid); }
        #pragma omp task shared(dr) default(none) firstprivate(pts, aux, mid, r) 
        { dr = rec(mid, r); }
        #pragma omp taskwait
        double d = std::min(dl, dr);

        /* merge by Y */
        std::merge(pts.begin() + l, pts.begin() + mid,
                   pts.begin() + mid, pts.begin() + r,
                   aux.begin(),
                   [](const Point& a, const Point& b) { return a.y < b.y; });
        std::copy(aux.begin(), aux.begin() + (r - l), pts.begin() + l);

        /* strip */
        std::vector<Point> strip;
        strip.reserve(r - l);
        for (size_t i = l; i < r; ++i)
            if (std::abs(pts[i].x - midX) < d)
                strip.push_back(pts[i]);

        /* compare each point to next up to 7 points */
        for (size_t i = 0; i < strip.size(); ++i)
            for (size_t j = i + 1; j < strip.size() && j <= i + 7; ++j)
                d = std::min(d, dist(strip[i], strip[j]));

        return d;
    };

    double result;
    #pragma omp parallel
    {
        #pragma omp single nowait
        result = rec(0, n);
    }

    return result;
}
