#pragma once
#include <vector>
#include <complex>
#include <cstdint>
#include <cmath>
#include <omp.h>

// optimize for gcc -O2, OpenMP, x86-64
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    // --- iterative in‑place radix‑2 FFT ------------------------------------
    // Pre‑compute twiddle tables (real/imag part separately for better cache)
    const double pi = 3.141592653589793238462643383279502884L;
    std::vector<double> wR(N / 2), wI(N / 2);
    for (std::size_t i = 0; i < N / 2; ++i)
    {
        double ang = -2.0 * pi * i / static_cast<double>(N);
        wR[i] = std::cos(ang);
        wI[i] = std::sin(ang);
    }

    std::size_t stage = 1;
    while (stage < N)
    {
        std::size_t half   = stage;
        std::size_t full   = stage << 1;
        std::size_t stride = N / full;        // index into wR/wI tables

#pragma omp parallel for schedule(static, 8)
        for (std::size_t i = 0; i < N; i += full)
        {
            for (std::size_t j = 0; j < half; ++j)
            {
                std::size_t idx  = i + j;
                std::size_t idx2 = idx + half;
                std::complex<double> t = x[idx2];
                // twiddle factor from pre‑computed tables
                double tr = t.real();
                double ti = t.imag();
                std::size_t wpos = j * stride;
                double wr = wR[wpos];
                double wi = wI[wpos];
                std::complex<double> tt(
                    tr * wr - ti * wi,
                    tr * wi + ti * wr
                );
                x[idx2] = x[idx] - tt;
                x[idx]  += tt;
            }
        }
        stage = full;
    }

    // --- bit‑reversal ------------------------------------------------------
    const std::size_t m = static_cast<std::size_t>(std::log2(N));
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = i;
        j = ((j & 0x5555555555555555ULL) << 1)
          | ((j & 0xaaaaaaaaaaaaaaaaULL) >> 1);
        j = ((j & 0x3333333333333333ULL) << 2)
          | ((j & 0xccccccccccccccccULL) >> 2);
        j = ((j & 0x0f0f0f0f0f0f0f0fULL) << 4)
          | ((j & 0xf0f0f0f0f0f0f0f0ULL) >> 4);
        j = ((j & 0x00ff00ff00ff00ffULL) << 8)
          | ((j & 0xff00ff00ff00ff00ULL) >> 8);
        j = ((j & 0x0000ffff0000ffffULL) << 16)
          | ((j & 0xffff0000ffff0000ULL) >> 16);
        j = ((j & 0x00000000ffffffffULL) << 32)
          | ((j & 0xffffffff00000000ULL) >> 32);
        j >>= (64 - m);
        if (j > i)
        {
            std::swap(x[i], x[j]);
        }
    }

    // --- conjugate (needed by the original implementation) ---------------
#pragma omp parallel for
    for (std::size_t i = 0; i < N; ++i)
    {
        x[i] = std::conj(x[i]);
    }
}
