/* Return the index of the value in the vector x that is closest to the math constant PI.
   Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
*/
size_t findClosestToPi(std::vector<double> const& x) {
    // Assume x is non‑empty; this matches the original contract.
    size_t bestIdx = 0;
    double bestDiff = std::abs(x[0] - M_PI);

    // Parallel reduction using a critical section for the tiny amount of
    // shared state. The vector is read‑only so the loop is safe for parallelism.
    #pragma omp parallel
    {
        size_t localIdx = 0;
        double localDiff = bestDiff;

        // Start the loop from 1 – index 0 is already processed.
        #pragma omp for nowait
        for (size_t i = 1; i < x.size(); ++i) {
            double d = std::abs(x[i] - M_PI);
            if (d < localDiff) {
                localDiff = d;
                localIdx  = i;
            }
        }

        // Update the global best with the local best found by this thread.
        #pragma omp critical
        {
            if (localDiff < bestDiff) {
                bestDiff = localDiff;
                bestIdx  = localIdx;
            }
        }
    }

    return bestIdx;
}
