#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

struct Result {
    int startTime, duration;
    float value;
};

/*
 * Sort vector of Result structs by start time in ascending order.
 * Uses a hybrid parallel sorting algorithm:
 *   * Each OpenMP thread sorts its own chunk with std::sort
 *   * Chunk boundaries are merged pairwise until a single sorted
 *     sequence remains.
 *
 * The algorithm preserves the exact behaviour of the original,
 * but is faster on multi‑core machines.
 */
inline void sortByStartTime(std::vector<Result>& results)
{
    const std::size_t n = results.size();
    if (n <= 1) return;                     // nothing to do

    const int numThreads = std::max(1, omp_get_max_threads());
    const std::size_t chunkSize = (n + numThreads - 1) / numThreads;

    /* ----- 1. Thread‑local sorting of chunks ----- */
#pragma omp parallel for schedule(static, 1) default(none) shared(results, n, chunkSize, numThreads)
    for (int t = 0; t < numThreads; ++t) {
        std::size_t start = t * chunkSize;
        std::size_t end   = std::min(start + chunkSize, n);
        if (start >= end) continue;          // thread has no work
        std::sort(results.begin() + start,
                  results.begin() + end,
                  [](const Result& a, const Result& b) noexcept {
                      return a.startTime < b.startTime;
                  });
    }

    /* ----- 2. Iterative pairwise merging ----- */
    std::size_t mergedStart = 0;            // next merge offset
    std::size_t stride      = chunkSize;    // distance between merged chunks

    // Temporary buffer for merging
    std::vector<Result> temp;
    temp.resize(n);

    while (stride < n) {
        const std::size_t merges = (n + stride * 2 - 1) / (stride * 2); // ceil

#pragma omp parallel for schedule(static, 1) default(none) \
        shared(results, temp, n, stride, mergedStart, merges)
        for (std::size_t m = 0; m < merges; ++m) {
            std::size_t left  = m * stride * 2;
            std::size_t mid   = std::min(left + stride, n);
            std::size_t right = std::min(left + stride * 2, n);

            std::size_t li = left;
            std::size_t ri = mid;
            std::size_t ti = left;

            while (li < mid && ri < right) {
                if (results[li].startTime <= results[ri].startTime)
                    temp[ti++] = std::move(results[li++]);
                else
                    temp[ti++] = std::move(results[ri++]);
            }
            while (li < mid) temp[ti++] = std::move(results[li++]);
            while (ri < right) temp[ti++] = std::move(results[ri++]);
        }

        // Swap roles of results and temp for the next pass
        results.swap(temp);
        stride *= 2;
    }
}
