#include <cstddef>
#include <omp.h>

/* 5‑point Jacobi stencil on an NxN grid.
 * input, output are row‑major dense vectors.
 * The routine keeps the exact semantics of the reference
 * implementation while exploiting parallelism, blocking
 * and minimal branching for maximum performance on x86‑64
 * with GCC -O2. */
inline void jacobi2D(const std::vector<double> &input,
                     std::vector<double>       &output,
                     size_t N)
{
    /* Use a cache‑block size that fits comfortably in L1/L2.
     * 64 bytes is a cache line, 256 bytes gives 256/8=32 elements per line.
     * A 32×32 block processes 32×32 double values ≈ 8 KiB per block. */
    constexpr size_t block = 32;

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; i += block) {
        const size_t i_end = std::min(i + block, N);

        /* --- inner blocks (no boundary checks) --- */
        for (size_t ii = i + 1; ii < i_end - 1; ++ii) {
            const size_t idx   = ii * N;
            const size_t idxm1 = (ii - 1) * N;
            const size_t idxp1 = (ii + 1) * N;
            double *out = &output[idx];
            const double *in  = &input[idx];
            const double *inm1 = &input[idxm1];
            const double *inp1 = &input[idxp1];
            size_t jj = 0;
            /* Vectorise the inner loop */
            for (; jj + 4 <= N; jj += 4) {
                out[jj]   = (in[jj]     + inm1[jj]     + inp1[jj]     +
                             in[jj-1]   + in[jj+1]) / 5.0;
                out[jj+1] = (in[jj+1]   + inm1[jj+1]   + inp1[jj+1]   +
                             in[jj]     + in[jj+2])   / 5.0;
                out[jj+2] = (in[jj+2]   + inm1[jj+2]   + inp1[jj+2]   +
                             in[jj+1]   + in[jj+3])   / 5.0;
                out[jj+3] = (in[jj+3]   + inm1[jj+3]   + inp1[jj+3]   +
                             in[jj+2]   + in[jj+4])   / 5.0;
            }
            /* tail */
            for (; jj < N; ++jj) {
                out[jj] = (in[jj] + inm1[jj] + inp1[jj] +
                           (jj > 0 ? in[jj-1] : 0.0) +
                           (jj + 1 < N ? in[jj+1] : 0.0)) / 5.0;
            }
        }

        /* --- first row of the block (i == 0) --- */
        for (size_t ii = i; ii < std::min(i+1, i_end); ++ii) {
            const size_t idx   = ii * N;
            const size_t idxp1 = (ii + 1) * N;
            double *out = &output[idx];
            const double *in  = &input[idx];
            const double *inp1 = &input[idxp1];
            size_t jj = 0;
            for (; jj + 4 <= N; jj += 4) {
                out[jj]   = (in[jj] + inp1[jj] +
                             (jj > 0 ? in[jj-1] : 0.0) +
                             (jj + 1 < N ? in[jj+1] : 0.0)) / 5.0;
                out[jj+1] = (in[jj+1] + inp1[jj+1] +
                             in[jj] + (jj+2 < N ? in[jj+2] : 0.0)) / 5.0;
                out[jj+2] = (in[jj+2] + inp1[jj+2] +
                             in[jj+1] + (jj+3 < N ? in[jj+3] : 0.0)) / 5.0;
                out[jj+3] = (in[jj+3] + inp1[jj+3] +
                             in[jj+2] + (jj+4 < N ? in[jj+4] : 0.0)) / 5.0;
            }
            for (; jj < N; ++jj) {
                out[jj] = (in[jj] + inp1[jj] +
                           (jj > 0 ? in[jj-1] : 0.0) +
                           (jj + 1 < N ? in[jj+1] : 0.0)) / 5.0;
            }
        }

        /* --- last row of the block (i == N-1) --- */
        for (size_t ii = std::max(i, (size_t)1); ii < i_end; ++ii) {
            const size_t idx   = ii * N;
            const size_t idxm1 = (ii - 1) * N;
